    const graph: number[][] = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        graph[u].push([v, w]);
    }

    // Dijkstra's algorithm with states
    // Each state is (node, hasSwitchUsed)
    // hasSwitchUsed is a boolean (0 or 1) indicating whether the switch at the node has been used
    const dist: number[][] = Array.from({ length: n }, () => Array(2).fill(Infinity));
    dist[0][0] = 0;

    // Priority queue for Dijkstra's algorithm
    const pq: [number, number, number][] = [[0, 0, 0]]; // [node, hasSwitchUsed, cost]

    while (pq.length > 0) {
        const [u, usedSwitch, cost] = pq.shift() as [number, number, number];

        // If we've reached the destination
        if (u === n - 1) {
            return cost;
        }

        // If this is not the shortest path to this state
        if (cost > dist[u][usedSwitch]) {
            continue;
        }

        // Explore neighbors
        for (const [v, w] of graph[u]) {
            // Regular edge traversal
            if (dist[v][usedSwitch] > cost + w) {
                dist[v][usedSwitch] = cost + w;
                pq.push([v, usedSwitch, dist[v][usedSwitch]]);
            }

            // Reverse edge traversal if switch hasn't been used
            if (!usedSwitch) {
                if (dist[v][1] > cost + 2 * w) {
                    dist[v][1] = cost + 2 * w;
                    pq.push([v, 1, dist[v][1]]);
                }
            }
        }
    }

    // If we can't reach the destination
    return -1;
}

